            content:
                '#!/bin/sh\n# scan-secrets.sh — Detect and REDACT secrets in a directory tree.\n# LOCAL ONLY: makes no network calls. Read-only. POSIX sh.\n# CRITICAL: never prints a raw secret — every matched value is redacted.\n#\n# Output: JSON {findings:[{file,line,type,redacted,likely_placeholder}],count}\n#         plus a human summary on stderr.\n#\n# Usage: scan-secrets.sh [DIR]   (DIR defaults to ".")\n#        scan-secrets.sh -h|--help\n\nset -eu\n\nprint_help() {\n    cat <<\'EOF\'\nscan-secrets.sh — local, read-only secret scanner with redaction\n\nUsage:\n  scan-secrets.sh [DIR]      Scan DIR (default: current directory)\n  scan-secrets.sh -h|--help  Show this help\n\nRuns locally only (no network). Every matched secret is REDACTED in output\n(first 4 + last 4 chars, middle masked). Placeholder-looking values are flagged.\nSkips .git, node_modules, vendor, and *example*/*sample* files.\nEOF\n}\n\nDIR="."\ncase "${1:-}" in\n    -h|--help) print_help; exit 0 ;;\n    "") : ;;\n    *) DIR="$1" ;;\nesac\n\nif [ ! -d "$DIR" ]; then\n    echo "error: \'$DIR\' is not a directory" >&2\n    exit 1\nfi\n\nif ! command -v grep >/dev/null 2>&1; then\n    echo \'{"findings":[],"count":0,"error":"grep not available"}\'\n    echo "error: \'grep\' is required but not installed" >&2\n    exit 1\nfi\n\n# Pattern table: "type|||regex" (||| separator avoids clashing with regex chars).\n# Patterns are grep -E (POSIX ERE) compatible.\nPATTERNS=$(cat <<\'PAT\'\naws_access_key_id|||AKIA[0-9A-Z]{16}\naws_temp_key_id|||ASIA[0-9A-Z]{16}\nprivate_key_block|||-----BEGIN ([A-Z]+ )?PRIVATE KEY-----\njwt|||eyJ[A-Za-z0-9_-]{10,}\\.[A-Za-z0-9_-]{10,}\\.[A-Za-z0-9_-]{10,}\nslack_token|||xox[baprs]-[0-9A-Za-z-]{10,}\nslack_webhook|||https://hooks\\.slack\\.com/services/[A-Za-z0-9/]+\ngithub_pat_classic|||ghp_[0-9A-Za-z]{36}\ngithub_oauth|||gho_[0-9A-Za-z]{36}\ngithub_server_refresh|||gh[sr]_[0-9A-Za-z]{36}\ngithub_fine_grained|||github_pat_[0-9A-Za-z_]{22,}\ngoogle_api_key|||AIza[0-9A-Za-z_-]{35}\nstripe_secret_key|||sk_live_[0-9A-Za-z]{16,}\nstripe_publishable_key|||pk_live_[0-9A-Za-z]{16,}\nsendgrid_key|||SG\\.[0-9A-Za-z_-]{22}\\.[0-9A-Za-z_-]{43}\nnpm_token|||npm_[0-9A-Za-z]{36}\npassword_assignment|||(password|passwd|pwd)[[:space:]]*[:=][[:space:]]*[\'"][^\'"]{6,}[\'"]\nsecret_assignment|||(secret|secret[_-]?key)[[:space:]]*[:=][[:space:]]*[\'"][^\'"]{8,}[\'"]\ntoken_assignment|||(token|auth[_-]?token|access[_-]?token)[[:space:]]*[:=][[:space:]]*[\'"][^\'"]{8,}[\'"]\napi_key_assignment|||(api[_-]?key|apikey)[[:space:]]*[:=][[:space:]]*[\'"][^\'"]{8,}[\'"]\npostgres_conn|||postgres(ql)?://[^:@/[:space:]]+:[^@/[:space:]]+@[^/[:space:]]+\nmysql_conn|||mysql://[^:@/[:space:]]+:[^@/[:space:]]+@[^/[:space:]]+\nmongodb_conn|||mongodb(\\+srv)?://[^:@/[:space:]]+:[^@/[:space:]]+@[^/[:space:]]+\nredis_conn|||redis://[^:@/[:space:]]*:[^@/[:space:]]+@[^/[:space:]]+\nbasic_auth_url|||https?://[^:@/[:space:]]+:[^@/[:space:]]+@[^/[:space:]]+\nazure_account_key|||AccountKey=[0-9A-Za-z+/=]{40,}\nPAT\n)\n\nTMPDIR_WORK=$(mktemp -d 2>/dev/null || mktemp -d -t secscan)\ntrap \'rm -rf "$TMPDIR_WORK"\' EXIT INT TERM\nRESULTS="$TMPDIR_WORK/results"\n: >"$RESULTS"\n\n# redact VALUE -> first4 + masked-middle + last4 ; full-mask if short.\nredact() {\n    v="$1"\n    len=${#v}\n    if [ "$len" -le 8 ]; then\n        i=0; out=""\n        while [ "$i" -lt "$len" ]; do out="$out*"; i=$((i+1)); done\n        printf \'%s\' "$out"\n        return\n    fi\n    head4=$(printf \'%s\' "$v" | cut -c1-4)\n    tail4=$(printf \'%s\' "$v" | cut -c$((len-3))-"$len")\n    mid=$((len-8))\n    [ "$mid" -gt 24 ] && mid=24\n    stars=""; i=0\n    while [ "$i" -lt "$mid" ]; do stars="$stars*"; i=$((i+1)); done\n    printf \'%s%s%s\' "$head4" "$stars" "$tail4"\n}\n\n# JSON-escape a string.\njson_escape() {\n    printf \'%s\' "$1" | sed \'s/\\\\/\\\\\\\\/g; s/"/\\\\"/g; s/\t/\\\\t/g\'\n}\n\n# Placeholder detection (case-insensitive) on the matched value or file path.\nis_placeholder() {\n    candidate="$1"\n    printf \'%s\' "$candidate" | grep -E -q -i \\\n        \'changeme|change-me|example|sample|dummy|placeholder|your-|xxxx|<[^>]+>|\\$\\{|\\{\\{|todo|fixme|\\*\\*\\*\' \\\n        && return 0\n    return 1\n}\n\n# File filter: skip binary / noisy dirs / example files.\n# We pass -I to grep to skip binary; dir pruning via --exclude-dir; example\n# files handled per-finding (still flagged but kept as placeholder).\nGREP_COMMON="-E -r -n -I --exclude-dir=.git --exclude-dir=node_modules --exclude-dir=vendor --exclude-dir=dist --exclude-dir=build"\n\n# Iterate patterns.\nprintf \'%s\\n\' "$PATTERNS" | while IFS= read -r entry; do\n    [ -n "$entry" ] || continue\n    type=$(printf \'%s\' "$entry" | sed \'s/|||.*//\')\n    regex=$(printf \'%s\' "$entry" | sed \'s/^[^|]*|||//\')\n\n    # grep returns non-zero when no matches — tolerate with || true.\n    # shellcheck disable=SC2086\n    grep $GREP_COMMON "$regex" "$DIR" 2>/dev/null | while IFS= read -r hit; do\n        [ -n "$hit" ] || continue\n        # hit format: file:line:content\n        file=$(printf \'%s\' "$hit" | cut -d: -f1)\n        line=$(printf \'%s\' "$hit" | cut -d: -f2)\n        content=$(printf \'%s\' "$hit" | cut -d: -f3-)\n\n        # Extract the matched value for redaction (re-run grep -oE on the line).\n        value=$(printf \'%s\' "$content" | grep -E -o "$regex" 2>/dev/null | head -n1)\n        [ -n "$value" ] || value="$content"\n\n        redacted=$(redact "$value")\n\n        placeholder="false"\n        if is_placeholder "$value" || is_placeholder "$file"; then\n            placeholder="true"\n        fi\n        case "$file" in\n            *example*|*sample*|*.template*|*fixture*) placeholder="true" ;;\n        esac\n\n        # Store TSV: type \\t file \\t line \\t redacted \\t placeholder\n        printf \'%s\\t%s\\t%s\\t%s\\t%s\\n\' \\\n            "$type" "$file" "$line" "$redacted" "$placeholder" >>"$RESULTS"\n    done || true\ndone || true\n\ncount=$(wc -l <"$RESULTS" | tr -d \' \')\n\n# ---- JSON output ----\n{\n    printf \'{"findings":[\'\n    first=1\n    while IFS="$(printf \'\\t\')" read -r type file line redacted placeholder; do\n        [ -n "$type" ] || continue\n        if [ "$first" -eq 1 ]; then first=0; else printf \',\'; fi\n        printf \'{"file":"%s","line":%s,"type":"%s","redacted":"%s","likely_placeholder":%s}\' \\\n            "$(json_escape "$file")" "$line" "$(json_escape "$type")" \\\n            "$(json_escape "$redacted")" "$placeholder"\n    done <"$RESULTS"\n    printf \'],"count":%s}\\n\' "$count"\n}\n\n# ---- Human summary ----\n{\n    echo ""\n    echo "=== Secret scan (LOCAL ONLY, values redacted) ==="\n    echo "Scanned: $DIR"\n    echo "Findings: $count"\n    if [ "$count" -gt 0 ]; then\n        echo "----"\n        while IFS="$(printf \'\\t\')" read -r type file line redacted placeholder; do\n            [ -n "$type" ] || continue\n            flag=""\n            [ "$placeholder" = "true" ] && flag="  [likely placeholder]"\n            echo "$file:$line  $type  $redacted$flag"\n        done <"$RESULTS"\n    fi\n    echo "(Never exfiltrate. Verify each finding in context before alarming.)"\n} >&2\n\nexit 0\n',
            bytes: 6877,
